// 取得郵件內容
const text = $input.item.json.text || $input.item.json.snippet || '';
const lines = text.split('\n').map(l => l.trim()).filter(Boolean);

// 解析函式：根據前綴抓取值
function pick(prefix) {
  const line = lines.find(l => l.includes(prefix));
  if (!line) return '';
  return line.split(prefix)[1]?.trim() || '';
}

// 抓取各欄位（根據你 EmailJS 模板的實際格式調整）
const userName = pick('姓名：') || pick('Name：') || pick('姓名:');
const userIG = pick('IG：') || pick('IG帳號：') || pick('Instagram：');
const shootType = pick('拍攝類型：') || pick('車種：') || pick('類型：');
const shootDate = pick('拍攝日期：') || pick('日期：'); // 格式: 2025-12-06
const shootClock = pick('拍攝時段：') || pick('時段：'); // 格式: 14:00-16:00
const plan = pick('方案：') || pick('Plan：');
const message = pick('備註：') || pick('需求：') || pick('Message：');
const userEmail = pick('Email：') || pick('信箱：');

// 組合完整時間（ISO 8601 格式給 Notion）
let startTime = null;
let endTime = null;

if (shootDate && shootClock) {
  if (shootClock.includes('-')) {
    const [start, end] = shootClock.split('-').map(s => s.trim());
    startTime = `${shootDate}T${start}:00+08:00`;
    endTime = `${shootDate}T${end}:00+08:00`;
  } else {
    startTime = `${shootDate}T${shootClock}:00+08:00`;
  }
} else if (shootDate) {
  startTime = `${shootDate}T00:00:00+08:00`;
}

// 組合 Notion Page 標題
const pageTitle = `${userName || '未命名'} - ${shootType || plan || '預約'}`;

// 回傳結構化資料
return {
  json: {
    // Notion 用
    pageTitle,
    userName,
    userIG,
    userEmail,
    shootType,
    shootDate,
    shootClock,
    plan,
    message,
    startTime,
    endTime,
    // 原始郵件資訊（備用）
    emailSubject: $input.item.json.subject,
    emailFrom: $input.item.json.from,
    emailDate: $input.item.json.date
  }
};
